SELECT s.id as id, s.category_id as category_id, s.name as name, s.price as price, s.status as status, s.description as description, s.image as image, s.update_time as update_time, c.name as category_name FROM setmeal s LEFT JOIN category c ON c.id = s.category_id
AND s.category_id = #{dto.categoryId}
AND s.name LIKE concat('%', #{dto.name}, '%')
AND s.status = #{dto.status}
ORDER BY s.update_time DESC

SELECT COUNT(*)
FROM setmeal
WHERE id = #{id}

SELECT s.id, s.category_id, s.`name`, s.price, s.`status`, s.description, s.image, s.update_time, c.`name` AS category_name FROM sky_take_out.setmeal s LEFT JOIN sky_take_out.category c ON s.category_id = c.id
AND s.category_id = #{categoryId}
AND s.status = #{status}
AND s.name LIKE concat('%',#{name},'%')
ORDER BY s.update_time DESC
